// ตัวแปรสำหรับเพลงที่จะเปิดตามเวลา
let mainFolder = "";  
let subFolder = "";   
let targetMood = "";
let playlist = [];

// ====================================================
// 🕒 TIMELINE LOGIC (ภาษาไทย + เพลงเอกลักษณ์ประจำช่วงเวลา)
// ====================================================

// 1. กลางคืน (00:00 - 04:00)
if (hour >= 0 && hour < 4) {
    mainFolder = "กลางคืน00.00-04.00";
    if (isRaining) {
        subFolder = "ฝนตก";
        targetMood = "Midnight Rain (Melancholy)";
        playlist = [
            "01_Midnight_Window_Echoes.wav", "02_Midnight_Window_Loops.wav",
            "03_Midnight_Windowpane.wav", "04_Rain_On_The_Fourth_Floor.wav",
            "05_Rain_On_The_Window_Loop.wav"
        ];
    } else {
        subFolder = "ปกติ";
        targetMood = "Lofi Midnight Vibes";
        playlist = [
            "01_Midnight_Dust_in_Reverse.wav", "02_Midnight_Hush_in_Reverse.wav",
            "03_Night_Static_Bloom.wav", "04_Reversed_Window_Light.wav",
            "05_Rewound_Midnight.wav", "06_Untitled.wav", 
            "07_Midnight_Queue_for_Tomorrow.wav", "08_Ghost_Glow_in_the_Rain.wav",
            "09_Rain_Dial_in_Reverse.wav", "10_Rewind_in_the_Rain.wav",
