    mainFolder = "ก่อนเช้า04.00-07.00";
    if (isRaining) {
        subFolder = "ฝนตก";
        targetMood = "Soft Rainlight";
        playlist = [
            "01_Misty_Dawn_Drizzle_v2.wav", "02_Misty_Dawn_Drizzle_v3.wav",
            "03_Misty_Dawn_Drizzle.wav", "04_Misty_Rain_Textures_v2.wav",
            "05_Misty_Rain_Textures.wav"
        ];
    } else {
        subFolder = "ปกติ";
        targetMood = "Pre-Dawn Echo";
        playlist = [
            "01_Morning_Haze_Loop.wav", "02_Morning_Haze_Motif.wav",
            "03_Morning_Haze_Over_Quiet_Streets.wav", "04_Morning_Haze_Rising.wav",
            "05_Morning_Haze_Silent_Hope.wav"
        ];
