    if (isRaining) {
        subFolder = "ฝนตก";
        targetMood = "Rainy Solitude";
        playlist = [
            "01_Rain_on_the_Window_v2.wav", "02_Rain_on_the_Window_Mug.wav",
            "03_Rain_on_the_Window_v2_Alt.wav", "04_Rain_on_the_Windowframe.wav"
