// ====================================================
// 🎲 ระบบสุ่ม: 90% All Day Lofi / 10% เพลงเฉพาะเวลา
// ====================================================

// ทอยเต๋า (สุ่มเลข 0-1) ถ้าได้น้อยกว่า 0.9 คือสุ่มโดนคลัง All Day
const rollAllDay = Math.random() < 0.90; 

let selectedPlaylist = [];
let selectedFolder = "";
let selectedMood = "";

if (rollAllDay) {
    selectedPlaylist = allDayPlaylist;
    selectedFolder = "All_Day_Lofi"; 
    selectedMood = "All Day Chill"; // อารมณ์เพลงตอนสุ่มโดนคลังกลาง
} else {
    selectedPlaylist = playlist;
    selectedFolder = `${mainFolder}/${subFolder}`; 
    selectedMood = targetMood;
}

// --- 3. 🎵 ระบบ Jingle & ระบบกันสุ่มซ้ำ (Anti-Repeat) ---

let finalPath = "";
let finalSong = "";
let finalMood = "";
let isJingle = false;

function getRandomSong(list) {
    if (list.length === 0) return "";
    if (list.length === 1) return list[0]; 

    let availableSongs = list.filter(song => song !== staticData.lastSong);
    if (availableSongs.length === 0) availableSongs = list; 

    return availableSongs[Math.floor(Math.random() * availableSongs.length)];
}

// ⚠️ เราจะเช็ค Jingle จากเวลาและสภาพอากาศ (currentFolderKey) ไม่ใช่โฟลเดอร์เพลงที่สุ่มได้
let currentFolderKey = `${mainFolder}/${subFolder}`; 
const memoryFolder = staticData.lastFolder; 

if (memoryFolder === '00_Station_ID') {
    // เพิ่งเล่น Jingle ไป -> กลับมาเปิดเพลงตามผลที่สุ่มได้ (90/10)
    finalSong = getRandomSong(selectedPlaylist);
    finalPath = `${selectedFolder}/${finalSong}`;
    finalMood = selectedMood;
    staticData.lastFolder = currentFolderKey; // บันทึกช่วงเวลา/อากาศปัจจุบัน
    staticData.lastSong = finalSong;
}
else if (currentFolderKey !== memoryFolder && memoryFolder !== undefined && memoryFolder !== 'TEST_MODE') {
    // ช่วงเวลาหรือสภาพอากาศเปลี่ยน -> เล่น Jingle คั่น
    finalPath = "00_Station_ID/Channel_Theme.wav"; 
    finalSong = "Channel_Theme.wav"; 
    finalMood = "Station ID (Switching)";
    isJingle = true;
    staticData.lastFolder = '00_Station_ID';
}
else {
    // ช่วงเวลา/อากาศเดิม -> เล่นเพลงตามผลที่สุ่มได้ (90/10)
    finalSong = getRandomSong(selectedPlaylist);
    finalPath = `${selectedFolder}/${finalSong}`;
    finalMood = selectedMood;
    staticData.lastFolder = currentFolderKey; // บันทึกช่วงเวลา/อากาศปัจจุบัน
    staticData.lastSong = finalSong;
}

// ⚠️ เช็ค Path 
const baseDir = "/Users/bourneken/Noah_Station/Music/Bourneken_Music_Library_Master/";

return {
    command_id: Math.floor(Date.now() / 1000),
    current_mood: finalMood,
    weather_status: weatherMain,
    filename: finalSong,
    full_path: `${baseDir}${finalPath}`,
    web_path: `music/Bourneken_Music_Library_Master/${finalPath}`, 
    is_jingle: isJingle,
    timestamp: Date.now()
};

// 1-Click Script: Convert Text to n8n Binary Data
for (const item of $input.all()) {
  const rawPath = item.json.full_path || "";
  const songName = rawPath.split('/').pop().replace('.mp3', '').replace('.wav', '');
  const jsContent = 'var currentSong = ' + JSON.stringify(songName) + ';';

  item.binary = {
    data: {
      data: Buffer.from(jsContent).toString('base64'),
      mimeType: 'application/javascript',
      fileName: 'song_data.js'
    }
  };
}
return $input.all();
